```c
#include <stdint.h>
#include <stdbool.h>
#include <string.h>
#include <stdio.h>

#define POOL_BLOCK_SIZE  64
#define POOL_BLOCK_COUNT 16

typedef struct {
    uint8_t memory[POOL_BLOCK_SIZE * POOL_BLOCK_COUNT];
    uint8_t *free_list[POOL_BLOCK_COUNT];
    uint32_t free_count;
} MemPool;

void pool_init(MemPool *pool) {
    pool->free_count = POOL_BLOCK_COUNT;
    for (uint32_t i = 0; i < POOL_BLOCK_COUNT; i++) {
        pool->free_list[i] = &pool->memory[i * POOL_BLOCK_SIZE];
    }
}

void *pool_alloc(MemPool *pool) {
    if (pool->free_count == 0) return NULL;
    pool->free_count--;
    return pool->free_list[pool->free_count];
}

bool pool_free(MemPool *pool, void *ptr) {
    uint8_t *p = (uint8_t *)ptr;
    // Bounds check
    if (p < pool->memory || p >= pool->memory + sizeof(pool->memory))
        return false;
    // Alignment check
    if ((p - pool->memory) % POOL_BLOCK_SIZE != 0)
        return false;
    if (pool->free_count >= POOL_BLOCK_COUNT)
        return false;
    pool->free_list[pool->free_count] = p;
    pool->free_count++;
    return true;
}

uint32_t pool_available(MemPool *pool) {
    return pool->free_count;
}
```

**Key features:**
- O(1) alloc and free (stack-based free list)
- No fragmentation (all blocks same size)
- Deterministic timing (critical for RTOS)
- Bounds and alignment checking on free
- No dynamic memory used — everything is statically allocated

